const items = $input.all();
if (!items || items.length === 0) return [];

const system = 'Voce destila REGRAS DE ESTILO EDITORIAL a partir de correcoes feitas por uma revisora medica em posts de blog. Proponha de 1 a 5 regras ACIONAVEIS, ESPECIFICAS e CURTAS (imperativas). Para cada uma: scope em {tom, estrutura, seo, factual, outro}. NAO invente regra factual ou de compliance CFM sem evidencia clara nas notas. Responda APENAS JSON valido: {"rules":[{"scope":"...","rule_text":"..."}]}';

const user = 'Notas de correcao acumuladas (cada linha = uma correcao):\n\n' +
  items.map((it, i) => (i+1) + '. [' + (it.json.pillar || '?') + '] ' + it.json.note_text).join('\n');

const log_ids = items.map(it => it.json.id);

return [{ json: { system, user, log_ids } }];

const raw = ($input.first().json.content?.[0]?.text) ?? ($input.first().json.text) ?? '';

// Strip markdown fences if present
let body = raw.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();

// Ensure starts with {
if (!body.startsWith('{')) body = '{' + body;

let parsed;
try {
  parsed = JSON.parse(body);
} catch(e) {
  const lastBrace = body.lastIndexOf('}');
  if (lastBrace > 0) {
    try { parsed = JSON.parse(body.slice(0, lastBrace + 1)); } catch(e2) {
      throw new Error('Parse Regras: JSON invalido: ' + e2.message + ' | raw: ' + body.slice(0, 200));
    }
  } else {
    throw new Error('Parse Regras: JSON invalido: ' + e.message + ' | raw: ' + body.slice(0, 200));
  }
}

const logIds = $('Montar Prompt').first().json.log_ids;
const validScopes = ['tom','estrutura','seo','factual','outro'];

const rules = parsed.rules || [];
if (rules.length === 0) return [];

return rules.map(r => ({
  json: {
    rule_text: r.rule_text,
    scope: validScopes.includes(r.scope) ? r.scope : 'outro',
    source_log_ids: logIds
  }
}));

// Pass through all INSERT regra items so Telegram has $json.id, scope, rule_text per item
const insertItems = $('INSERT regra').all();
return insertItems.map(it => ({
  json: { id: it.json.id, rule_text: it.json.rule_text, scope: it.json.scope }
}));

